var hui = Vec2<bool>(n + 1, n + 1);
fa(i, 1, n)hui[i][i] = hui[i][i - 1] = 1;
fa(len, 2, n)fa(i, 1, n) {
	int j = i + len - 1;
	if (j > n)break;
	if (hui[i + 1][j - 1] and s[i] == s[j]) {
		hui[i][j] = 1;
	}
}

var hui = Vec2<bool>(n + 1, n + 1);
fa(i, 1, n) {
    // 奇数长度回文
    for (int l = i, r = i; l >= 1 and r <= n and s[l-1] == s[r-1]; l--, r++)
    	hui[l][r] = true;
    // 偶数长度回文
    for (int l = i, r = i + 1; l >= 1 and r <= n and s[l-1] == s[r-1]; l--, r++) 
    	hui[l][r] = true;
}
